SELECT DISTINCT ?team ?teamLabel (COUNT(*) AS ?wins) WHERE {
  ?edition wdt:P3450 wd:Q39086035 ;
           wdt:P1346 ?team .
  ?team rdfs:label ?teamLabel .
  FILTER(LANG(?teamLabel) = 'en')
} GROUP BY ?team ?teamLabel ORDER BY DESC(?wins) LIMIT 1

